### 2. IORingZoneLoader.cpp (Implementation)

```cpp
// src/iouring_zone_loader.cpp
#include "iouring_zone_loader.h"
#include <chrono>

namespace RawrXD::IO {

IORingZoneLoader::IORingZoneLoader(const IORingConfig& config) {
    IORING_CREATE_FLAGS flags = {};
    flags.Required = IORING_CREATE_REQUIRED_FLAGS_NONE;
    flags.Advisory = IORING_CREATE_ADVISORY_FLAGS_NONE;
    
    HRESULT hr = CreateIoRing(
        IORING_VERSION_3,
        flags,
        config.queueDepth,      // Submission queue size
        config.queueDepth,      // Completion queue size
        &hRing_
    );
    
    if (FAILED(hr)) {
        // Fallback to IORING_VERSION_2 for older Windows 11
        hr = CreateIoRing(
            IORING_VERSION_2,
            flags,
            config.queueDepth,
            config.queueDepth,
            &hRing_
        );
    }
    
    if (SUCCEEDED(hr)) {
        hCompletionEvent_ = CreateEventW(nullptr, FALSE, FALSE, nullptr);
    }
}

IORingZoneLoader::~IORingZoneLoader() {
    if (hRing_) {
        CloseIoRing(hRing_);
    }
    if (hCompletionEvent_) {
        CloseHandle(hCompletionEvent_);
    }
}

bool IORingZoneLoader::Initialize(HANDLE hFile) {
    hFile_ = hFile;
    
    // Enable completion event
    if (hCompletionEvent_) {
        SetIoRingCompletionEvent(hRing_, hCompletionEvent_);
    }
    
    return hRing_ != nullptr && hFile_ != INVALID_HANDLE_VALUE;
}

bool IORingZoneLoader::SubmitZoneRead(uint64_t fileOffset,
                                      void* buffer,
                                      uint32_t size,
                                      void* userContext) {
    if (!hRing_ || !hFile_) return false;
    
    IORING_BUFFER_REF bufRef = {};
    bufRef.Kind = IORING_BUFFER_REF_KIND_POINTER;
    bufRef.Pointer = buffer;
    
    IORING_HANDLE_REF fileRef = {};
    fileRef.Kind = IORING_HANDLE_REF_KIND_HANDLE;
    fileRef.Handle = hFile_;
    
    // Build IORING_OP_READ operation
    IORING_OP_READ_PARAMS readParams = {};
    readParams.file = fileRef;
    readParams.buffer = bufRef;
    readParams.offset = fileOffset;
    readParams.length = size;
    readParams.key = 0;
    
    IORING_OP_PARAMS params = {};
    params.OpCode = IORING_OP_READ;
    params.Read = readParams;
    
    uint32_t submitted = 0;
    HRESULT hr = SubmitIoRing(hRing_, 0, 1, &submitted);
    
    if (SUCCEEDED(hr) && submitted == 1) {
        // Track pending
        std::lock_guard<std::mutex> lock(pendingMutex_);
        static uint32_t opId = 0;
        uint32_t id = ++opId;
        pendingOps_[id] = {userContext, 
            GetTickCount64(), size};
        submittedOps_++;
        return true;
    }
    
    return false;
}

bool IORingZoneLoader::SubmitZoneBatch(const ZoneRequest requests[],
                                       uint32_t count) {
    if (!hRing_ || count == 0) return false;
    
    uint32_t submittedTotal = 0;
    
    for (uint32_t i = 0; i < count; ++i) {
        const auto& req = requests[i];
        
        IORING_BUFFER_REF bufRef = {};
        bufRef.Kind = IORING_BUFFER_REF_KIND_POINTER;
        bufRef.Pointer = req.buffer;
        
        IORING_HANDLE_REF fileRef = {};
        fileRef.Kind = IORING_HANDLE_REF_KIND_HANDLE;
        fileRef.Handle = hFile_;
        
        IORING_OP_READ_PARAMS readParams = {};
        readParams.file = fileRef;
        readParams.buffer = bufRef;
        readParams.offset = req.fileOffset;
        readParams.length = req.size;
        
        IORING_OP_PARAMS params = {};
        params.OpCode = IORING_OP_READ;
        params.Read = readParams;
        
        // Chain operations: set IOSQE_IO_LINK equivalent
        if (i < count - 1) {
            // Windows IORING doesn't have explicit chaining,
            // but batch submission achieves similar effect
        }
        
        uint32_t submitted = 0;
        HRESULT hr = SubmitIoRing(hRing_, 0, 1, &submitted);
        
        if (SUCCEEDED(hr)) {
            submittedTotal += submitted;
        }
    }
    
    return submittedTotal == count;
}

uint32_t IORingZoneLoader::PollCompletions(uint32_t maxCompletions,
                                           CompletionResult results[]) {
    if (!hRing_) return 0;
    
    IORING_CQE cqe;
    uint32_t completed = 0;
    
    while (completed < maxCompletions) {
        HRESULT hr = PopIoRingCompletion(hRing_, &cqe);
        
        if (hr == HRESULT_FROM_WIN32(ERROR_MORE_DATA)) {
            // Completion available
            results[completed].result = cqe.ResultCode;
            results[completed].bytesTransferred = cqe.Information;
            
            // Map back to user context
            {
                std::lock_guard<std::mutex> lock(pendingMutex_);
                auto it = pendingOps_.find(cqe.UserData);
                if (it != pendingOps_.end()) {
                    results[completed].userContext = it->second.userContext;
                    
                    // Calculate latency
                    auto now = GetTickCount64();
                    results[completed].latencyUs = 
                        (now - it->second.submitTime) * 1000.0;
                    
                    pendingOps_.erase(it);
                }
            }
            
            completed++;
            completedOps_++;
        } else {
            // No more completions
            break;
        }
    }
    
    return completed;
}

bool IORingZoneLoader::RegisterBufferPool(void* buffers[],
                                          uint32_t bufferSize,
                                          uint32_t count) {
    if (!hRing_) return false;
    
    registeredBuffers_.clear();
    bufferPool_.clear();
    
    for (uint32_t i = 0; i < count; ++i) {
        IORING_BUFFER_INFO bufInfo = {};
        bufInfo.Address = buffers[i];
        bufInfo.Length = bufferSize;
        
        IORING_BUFFER_REF ref = {};
        ref.Kind = IORING_BUFFER_REF_KIND_REGISTERED;
        ref.RegisteredBuffer.Index = i;
        ref.RegisteredBuffer.Offset = 0;
        
        // Register with kernel
        HRESULT hr = BuildIoRingRegisterBuffers(
            hRing_,
            1,
            &bufInfo,
            i
        );
        
        if (SUCCEEDED(hr)) {
            registeredBuffers_.push_back(ref);
            bufferPool_.push_back(buffers[i]);
        }
    }
    
    return registeredBuffers_.size() == count;
}

IORingZoneLoader::Stats IORingZoneLoader::GetStats() const {
    Stats s;
    s.submittedOps = submittedOps_.load();
    s.completedOps = completedOps_.load();
    
    // Calculate averages from pending ops
    std::lock_guard<std::mutex> lock(pendingMutex_);
    if (!pendingOps_.empty()) {
        double totalLatency = 0;
        std::vector<double> latencies;
        
        for (const auto& [id, op] : pendingOps_) {
            auto now = GetTickCount64();
            double lat = (now - op.submitTime) * 1000.0;
            totalLatency += lat;
            latencies.push_back(lat);
        }
        
        s.avgLatencyUs = totalLatency / pendingOps_.size();
        
        // P99
        std::sort(latencies.begin(), latencies.end());
        size_t p99Idx = latencies.size() * 99 / 100;
        s.p99LatencyUs = latencies[p99Idx];
    }
    
    return s;
}

} // namespace RawrXD::IO
